import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function classifyWallet(walletAddress) {
  const txns = await client.TransactionService.getTransactionsForAddressV3(
    "eth-mainnet", walletAddress, { noSpam: true }
  );
  const items = txns.data?.items ?? [];
  const contractDeployments = items.filter(tx => !tx.to_address).length;
  const contractInteractions = items.filter(tx => tx.to_address && tx.log_events?.length > 0).length;
  const type = contractDeployments > 2 ? "developer"
    : contractInteractions / items.length > 0.8 ? "bot"
    : "retail";
  return { walletAddress, type, contractDeployments, contractInteractions };
}
